sql:
SELECT fund_name, contact_email, total_assets
FROM hedge_funds
WHERE risk_rating = 'High' AND fund_type = 'Equity';

SELECT fund_managers.manager_name, hedge_funds.fund_name
FROM fund_managers
INNER JOIN hedge_funds ON fund_managers.manager_id = hedge_funds.fund_manager_id;

external_knowledge:
- "captains of the fleets" refers to the fund managers;
- "highest sails" metaphorically refers to the highest average leverage ratios;
- "set the highest sails" indicates funds with high leverage ratios;
- "size of their fleets" refers to the total assets under management;
- "top three most daring sail-setters" means the top three funds based on average leverage ratio.

sql:
SELECT fund_name, total_assets, risk_rating
FROM hedge_funds
ORDER BY total_assets DESC;

SELECT DISTINCT AVG(leverage_ratio) AS avg_leverage_ratio
FROM hedge_funds
WHERE total_assets > 1000000000 AND risk_rating IN ('High', 'Medium');

SELECT fund_name, fund_type, performance_fee
FROM hedge_funds
WHERE performance_fee > (SELECT AVG(performance_fee) FROM hedge_funds);

SELECT fund_name 
FROM hedge_funds 
WHERE fund_id = 1;

SELECT action
FROM audits
WHERE audit_id = 0;
